import {useEffect} from 'react';
import {Accelerometer} from 'expo-sensors';
export function useShakeUndo(onShake: () => void) { useEffect(() => { Accelerometer.setUpdateInterval(200); const sub = Accelerometer.addListener(({x, y, z}) => { const mag = Math.sqrt(x*x + y*y + z*z); if (mag > 2.5) onShake(); }); return () => sub.remove(); }, [onShake]); }

