// StepCounterRingWithGoal.tsx
import React, {useEffect, useMemo, useState} from 'react';
import {StyleSheet, View, Text, Pressable} from 'react-native';
import {Canvas, Path, Circle, Skia} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, Easing} from 'react-native-reanimated';

type Datum = {id: string; label: string; value: number; color: string};
function arcPath(cx: number, cy: number, radius: number, start: number, end: number) {
  const p = Skia.Path.Make();
  p.moveTo(cx, cy);
  p.addArc({x: cx - radius, y: cy - radius, width: radius * 2, height: radius * 2}, start, end - start);
  p.close();
  return p;
}
export function StepCounterRingWithGoal({data, size = 220}: {data: Datum[]; size?: number}) {
  const [selected, setSelected] = useState<string | null>(null);
  const progress = useSharedValue(0);
  useEffect(() => { progress.value = withTiming(1, {duration: 520, easing: Easing.out(Easing.cubic)}); }, [progress]);
  const total = Math.max(1, data.reduce((sum, d) => sum + d.value, 0));
  const slices = useMemo(() => {
    let cursor = -90;
    return data.map((d) => {
      const sweep = (d.value / total) * 360;
      const path = arcPath(size / 2, size / 2, size / 2 - 12, cursor, cursor + sweep);
      cursor += sweep;
      return {...d, path};
    });
  }, [data, size, total]);
  return (
    <View style={styles.wrap} accessibilityRole="image" accessibilityLabel="Step counter ring with goal">
      <Canvas style={{width: size, height: size}}>
        {slices.map((slice) => <Path key={slice.id} path={slice.path} color={selected === slice.id ? '#0f766e' : slice.color} />)}
        <Circle cx={size / 2} cy={size / 2} r={size * 0.26} color="#ffffff" />
      </Canvas>
      <View style={styles.legend}>{data.map((d) => <Pressable key={d.id} onPress={() => setSelected(d.id)} accessibilityRole="button" accessibilityLabel={`${d.label}: ${d.value}`} style={styles.row}><View style={[styles.swatch, {backgroundColor: d.color}]} /><Text>{d.label}</Text></Pressable>)}</View>
    </View>
  );
}
const styles = StyleSheet.create({wrap: {alignItems: 'center', gap: 12}, legend: {alignSelf: 'stretch', gap: 8}, row: {minHeight: 44, flexDirection: 'row', alignItems: 'center', gap: 8}, swatch: {width: 12, height: 12, borderRadius: 6}});

